def solve(arg1: dict) -> dict:
    # Validate inputs
    if 'challengeId' not in arg1 or not arg1['challengeId']:
        return {'error': 'Challenge ID cannot be empty'}

    challenge_id = arg1['challengeId']

    # Simulated challenge data for demonstration purposes
    challenges = {
        '12345': {'phaseEndTime': '2023-10-15T12:00:00Z'},
        '67890': {'phaseEndTime': '2023-10-20T12:00:00Z'}
    }

    # Check if the challenge exists
    if challenge_id not in challenges:
        return {'error': 'Challenge not found'}

    # Return the phase end time for the valid challenge
    return {'phaseEndTime': challenges[challenge_id]['phaseEndTime']}
